interface Props {
  size?: "very-small" | "small" | "medium" | "large";
}

export const Logo = ({ size = "medium" }: Props) => {
  let sizeLogo: number;

  switch (size) {
    case "very-small":
      sizeLogo = 34;
      break;
    case "small":
      sizeLogo = 61;
      break;
    case "medium": //Default
      sizeLogo = 88;
      break;
    case "large":
      sizeLogo = 140;
      break;
  }

  return (
    <div>
      <svg
        width={sizeLogo}
        height="130"
        viewBox="0 0 130 130"
        fill="none"
        xmlns="http://www.w3.org/2000/svg"
        xmlnsXlink="http://www.w3.org/1999/xlink"
      >
        <rect width="130" height="130" fill="url(#pattern0_22_90)" />
        <defs>
          <pattern
            id="pattern0_22_90"
            patternContentUnits="objectBoundingBox"
            width="1"
            height="1"
          >
            <use xlinkHref="#image0_22_90" transform="scale(0.00133333)" />
          </pattern>
          <image
            id="image0_22_90"
            width="750"
            height="750"
            preserveAspectRatio="none"
            xlinkHref="data:image/png;base64,"
          />
        </defs>
      </svg>
    </div>
  );
};
